Board 1 refers to a specific board associated with the signals in the database; 
 The signals' current status and last status details include the maximum status value, last status time, fault status, and fault description;
 The configuration settings include the configuration key, value, and creation time.

sql:
SELECT u.user_name
FROM users u
JOIN device_instances di ON u.user_id IN (
    SELECT instance_id FROM device_boards WHERE user_id IN (
        SELECT user_id FROM user_access WHERE feature = 'device_instance'
    )
)
WHERE u.role = 'engineer'
AND di.next_maintenance_due >= DATE('now')
AND di.next_maintenance_due <= DATE('now', '+30 days');

SELECT name
FROM signals
WHERE is_active = 1 AND board_id = (SELECT board_id FROM boards WHERE board_name = 'Power Board');

SELECT name
FROM signals
WHERE fault_threshold > 100;
